-- ========== ANNOUNCEMENT_TB ==========
CREATE TABLE "HR"."ANNOUNCEMENT_TB" 
   (	"ANNOUNCEMENT_ID" NUMBER NOT NULL ENABLE, 
	"MEMBER_ID" NUMBER NOT NULL ENABLE, 
	"TITLE" VARCHAR2(200) NOT NULL ENABLE, 
	"CONTENT" CLOB NOT NULL ENABLE, 
	"VIEW_CNT" NUMBER DEFAULT 0 NOT NULL ENABLE, 
	"REG_DATE" DATE DEFAULT SYSDATE NOT NULL ENABLE, 
	 CONSTRAINT "PK_ANNOUNCEMENT" PRIMARY KEY ("ANNOUNCEMENT_ID")
  USING INDEX;

