-- ========== INQUIRY_TB ==========
CREATE TABLE "HR"."INQUIRY_TB" 
   (	"INQUIRY_ID" NUMBER, 
	"MEMBER_ID" NUMBER NOT NULL ENABLE, 
	"TITLE" VARCHAR2(200) NOT NULL ENABLE, 
	"CONTENT" CLOB NOT NULL ENABLE, 
	"ANSWER" CLOB, 
	"STATUS" VARCHAR2(20) DEFAULT '대기중', 
	"CREATED_AT" DATE DEFAULT SYSDATE, 
	"ANSWERED_AT" DATE, 
	 PRIMARY KEY ("INQUIRY_ID")
  USING INDEX;

