-- ========== MAPLE_CHARACTER ==========
CREATE TABLE "HR"."MAPLE_CHARACTER" 
   (	"ID" NUMBER(19,0) NOT NULL ENABLE, 
	"CHAR_CLASS" VARCHAR2(50 CHAR), 
	"CHAR_LEVEL" NUMBER(10,0), 
	"CHAR_NAME" VARCHAR2(50 CHAR), 
	"CHAR_OCID" VARCHAR2(100 CHAR), 
	"COMBAT_POWER" NUMBER(19,0), 
	"GUILD_NAME" VARCHAR2(50 CHAR), 
	"IMAGE_URL" VARCHAR2(2000), 
	"IS_VALID" NUMBER(1,0) NOT NULL ENABLE, 
	"MAPLE_ACCOUNT_ID" NUMBER(19,0) NOT NULL ENABLE, 
	 CHECK (IS_VALID in (0,1)) ENABLE, 
	 PRIMARY KEY ("ID")
  USING INDEX;

